// Vault capacity formula: L1=30k, L10=200k, L20=1M, L30=20M
// Using power curve: capacity = 30000 * (level)^2.15
export const getVaultCapacity = (level) => {
  const base = 30000;
  const curve = Math.pow(level, 2.15);
  const scaling = 20000000 / Math.pow(30, 2.15); // normalize to hit 20M at L30
  return Math.round(base * curve * scaling / Math.pow(30, 2.15));
};

// Mine/Mill production: L1=3k/hr (15k storage), L30=80k/hr (750k storage)
export const getMineProduction = (level) => {
  const production = 3000 + (level - 1) * (80000 - 3000) / 29;
  const storage = 15000 + (level - 1) * (750000 - 15000) / 29;
  return { production_per_hour: Math.round(production), storage: Math.round(storage) };
};

// Alias for backward compatibility
export const getVaultProduction = getMineProduction;

// Upgrade cost & time formulas (L = target level, range 2–30, n = L-2 so n∈[0,28])
//
// Time:
//   Non-TH: 30 * 1.4546^n  (L2=30s → L30=12 days)
//   TH:     120 * 1.4111^n (L2=120s → L30=24 days)
//
// Cost:
//   Non-TH (gold or mana): 500  * 1.4974^n (L2=500  → L30=40M)
//   TH     (gold):         1000 * 1.5036^n (L2=1000 → L30=100M)
//
// Currency rule:
//   gold_mine & gold_mill (Gold Vault) cost MANA to upgrade.
//   All other buildings cost GOLD.

export const getUpgradeCost = (buildingType, currentLevel) => {
  const def = BUILDING_DEFS[buildingType];
  if (!def) return { gold: 0, mana: 0, seconds: 0, gems: 0 };

  const L = currentLevel + 1; // target level (2–30)
  const n = L - 2; // exponent (0–28)

  let seconds, resourceCost;

  // Wall-specific formula: L1=100g/1000hp → L30=1.2Mg/500khp
  if (buildingType === 'wall') {
    resourceCost = Math.round(100 * Math.pow(1.3594, n)); // 100 → 1.2M
    seconds = Math.round(10 * Math.pow(1.45, n)); // faster upgrade time
  } else if (def.isTownHall) {
    seconds = Math.round(120 * Math.pow(1.4111, n));
    resourceCost = Math.round(1000 * Math.pow(1.5036, n));
  } else {
    seconds = Math.round(30 * Math.pow(1.4546, n));
    resourceCost = Math.round(500 * Math.pow(1.4974, n));
  }

  // Gem speed-up: ceil((minutes)^1.2) — steeper power curve
  const gems = Math.ceil(Math.pow(Math.max(seconds / 60, 1), 1.2));

  // Apply currency based on building type
  const usesMana = def.costCurrency === "mana";
  return {
    gold: usesMana ? 0 : resourceCost,
    mana: usesMana ? resourceCost : 0,
    seconds,
    gems
  };
};

// Building HP formulas (non-linear scaling)
// Town Hall: L1=2k → L15=90k → L23=225k → L30=750k
export const getTownHallHP = (level) => {
  if (level === 1) return 2000;
  if (level === 15) return 90000;
  if (level === 23) return 225000;
  if (level === 30) return 750000;
  // Interpolate using power curve
  if (level < 15) {
    const n = level - 1;
    return Math.round(2000 * Math.pow(1.332, n)); // 2k → 90k at L15
  } else if (level < 23) {
    const n = level - 15;
    return Math.round(90000 * Math.pow(1.121, n)); // 90k → 225k at L23
  } else {
    const n = level - 23;
    return Math.round(225000 * Math.pow(1.163, n)); // 225k → 750k at L30
  }
};

// Hero Base: L1=700 → L30=200k
export const getHeroBaseHP = (level) => {
  if (level === 1) return 700;
  if (level === 30) return 200000;
  const n = level - 1;
  return Math.round(700 * Math.pow(1.223, n)); // 700 → 200k at L30
};

// Mills/Mines: L1=600 → L30=180k
export const getMineHP = (level) => {
  if (level === 1) return 600;
  if (level === 30) return 180000;
  const n = level - 1;
  return Math.round(600 * Math.pow(1.217, n)); // 600 → 180k at L30
};

// Army Camp: L1=1k → L30=250k
export const getArmyCampHP = (level) => {
  if (level === 1) return 1000;
  if (level === 30) return 250000;
  const n = level - 1;
  return Math.round(1000 * Math.pow(1.226, n)); // 1k → 250k at L30
};

// Defense Tower: L1=1.5k → L30=300k
export const getDefenseTowerHP = (level) => {
  if (level === 1) return 1500;
  if (level === 30) return 300000;
  const n = level - 1;
  return Math.round(1500 * Math.pow(1.224, n)); // 1.5k → 300k at L30
};

// Altar: L1=2k → L100=330k
export const getAltarHP = (level) => {
  if (level === 1) return 2000;
  if (level === 100) return 330000;
  const n = level - 1;
  return Math.round(2000 * Math.pow(1.053, n)); // 2k → 330k at L100
};

// Wall: L1=500 → L15=50k → L30=300k
export const getWallHP = (level) => {
  if (level === 1) return 500;
  if (level === 15) return 50000;
  if (level === 30) return 300000;
  if (level < 15) {
    const n = level - 1;
    return Math.round(500 * Math.pow(1.393, n)); // 500 → 50k at L15
  } else {
    const n = level - 15;
    return Math.round(50000 * Math.pow(1.064, n)); // 50k → 300k at L30
  }
};

// Generic building (not upgraded): base 500 HP
export const getGenericBuildingHP = (level) => 500;

// Wrapper to get max HP for any building type
// Checks custom overrides from buildingStats first
export const getBuildingMaxHP = (buildingType, level) => {
  // Check custom override persisted in localStorage
  try {
    const store = JSON.parse(localStorage.getItem("building_hp_overrides_v1") || "{}");
    const override = store[`${buildingType}__${level}`];
    if (override != null && !isNaN(override)) return override;
  } catch {}
  switch (buildingType) {
    case 'town_hall':return getTownHallHP(level);
    case 'hero_base':return getHeroBaseHP(level);
    case 'gold_mine':
    case 'mana_mine':return getMineHP(level);
    case 'gold_mill':
    case 'mana_vault':return getMineHP(level);
    case 'army_camp':return getArmyCampHP(level);
    case 'defense_tower':return getDefenseTowerHP(level);
    case 'altar':return getAltarHP(level);
    case 'wall':return getWallHP(level);
    default:return getGenericBuildingHP(level);
  }
};

// Gear upgrade cost: L1=1000 shards → L30=1M shards
export const getGearUpgradeCost = (level) => {
  if (level >= 30) return 1000000;
  const n = level - 1;
  return Math.round(1000 * Math.pow(1.5479, n)); // 1000 → 1M at L30
};

// Spells Temple upgrade cost: L1=2000 mana → L10=2M mana
export const getSpellsTempleUpgradeCost = (level) => {
  if (level >= 10) return 2000000;
  const n = level - 1;
  return Math.round(2000 * Math.pow(2.1544, n)); // 2000 → 2M at L10
};

// Spells Temple usage cost: L1=200 mana → L10=200k mana
export const getSpellsTempleUsageCost = (level) => {
  if (level >= 10) return 200000;
  const n = level - 1;
  return Math.round(200 * Math.pow(2.1544, n)); // 200 → 200k at L10
};

// Town Hall level cap for building upgrades
// All buildings can upgrade to level 30
export const getBuildingLevelCap = (buildingType, townHallLevel) => {
  return 30; // All buildings can go to level 30
};

// Auto-collect intervals based on TH level (in hours)
export const getAutoCollectIntervalHours = (townHallLevel) => {
  if (townHallLevel >= 30) return 1;
  if (townHallLevel >= 23) return 2;
  if (townHallLevel >= 15) return 4;
  return null; // No auto-collect
};

// Pack definitions
export const PACK_TYPES = {
  S: { name: "Small Pack", capacity: 500, color: "#22c55e", icon: "📦" },
  M: { name: "Medium Pack", capacity: 5000, color: "#3b82f6", icon: "📦" },
  L: { name: "Large Pack", capacity: 50000, color: "#a855f7", icon: "📦" },
  XL: { name: "Extra Large Pack", capacity: 500000, color: "#fbbf24", icon: "📦" }
};

// Gem cost tiers for pack conversion
export const getGemCostForOverflow = (overflowAmount) => {
  if (overflowAmount > 100000) return 150;
  if (overflowAmount > 10000) return 50;
  if (overflowAmount > 0) return 10;
  return 0;
};

// Calculate optimal pack distribution
export const calculatePackDistribution = (overflowAmount, packType) => {
  const packCap = PACK_TYPES[packType].capacity;
  const packCount = Math.min(Math.floor(overflowAmount / packCap), 65535);
  const storedAmount = packCount * packCap;
  const wastedAmount = overflowAmount - storedAmount;
  return { packCount, storedAmount, wastedAmount };
};

// Standalone gem cost for a given number of remaining seconds
export const getGemsForSeconds = (seconds) =>
Math.ceil(Math.pow(Math.max(seconds / 60, 1), 0.75));

export const getUpgradeSecondsRemaining = (building) => {
  if (!building.is_upgrading || !building.upgrade_started_at) return 0;
  const elapsed = (Date.now() - new Date(building.upgrade_started_at).getTime()) / 1000;
  return Math.max(0, building.upgrade_duration_seconds - elapsed);
};

export const formatTime = (seconds) => {
  if (seconds <= 0) return "Done";
  const d = Math.floor(seconds / 86400);
  const h = Math.floor(seconds % 86400 / 3600);
  const m = Math.floor(seconds % 3600 / 60);
  const s = Math.floor(seconds % 60);
  if (d > 0) return `${d}d ${h}h`;
  if (h > 0) return `${h}h ${m}m`;
  if (m > 0) return `${m}m ${s}s`;
  return `${s}s`;
};

export const GRID_SIZE = 94;
export const TILE_W = 48;
export const TILE_H = 24;

export const gridToScreen = (gx, gy) => {
  const x = (gx - gy) * (TILE_W / 2);
  const y = (gx + gy) * (TILE_H / 2);
  return { x, y };
};

export const screenToGrid = (sx, sy) => {
  const gx = Math.round(sx / TILE_W + sy / TILE_H);
  const gy = Math.round(-sx / TILE_W + sy / TILE_H);
  return { gx, gy };
};

